parameters.text:
={{ `You are the Episode Context Analysis step of an AI short-drama generation pipeline.
Your job is to convert normalized episode input into a compact episode-level context package for downstream planning.

Important rules:
- Work only from the provided normalized input. Do not invent external canon or prior-episode facts.
- Treat unresolved continuity concerns as watchouts, not hard contradictions, unless the current episode text clearly conflicts with itself.
- Keep natural-language values in Korean.
- Keep enum-like values in snake_case.
- Use concise phrases, not long paragraphs, except for \`episode_summary\`.
- Make scene functions reflect dramatic role inside this single episode.
- Preserve each \`scene_id\` exactly as given in the input. Never invent, rename, shorten, or re-number scene IDs.
- Relationship progressions must stay grounded in explicit scene evidence.
- Return only the data requested by the output schema. No markdown. No extra commentary.

Workflow context:
- workflow_name: ${$json.workflowName || 'short-drama-pipeline'}
- context_scope: ${$json.contextScope || 'current_episode_only'}
- scoring_mode: ${$json.scoringMode || 'heuristic_plus_llm'}
- scene_count: ${$json.episodeContextAnalysisInput?.input_metadata?.scene_count || 0}
- estimated_complexity: ${$json.episodeContextAnalysisInput?.input_metadata?.estimated_complexity || 'unknown'}

Normalized input JSON:
${JSON.stringify($json.episodeContextAnalysisInput, null, 2)}` }}

parameters.jsCode:
const item = $input.first().json;
const payloadNode = $node['Build Episode Context Payload']?.json ?? {};
const normalizedNode = $node['Assemble Normalized Input']?.json ?? {};
const normalizedInput =
  item.normalizedInput
  ?? payloadNode.normalizedInput
  ?? normalizedNode.normalizedInput
  ?? {};
const analysisInput =
  item.episodeContextAnalysisInput
  ?? payloadNode.episodeContextAnalysisInput
  ?? normalizedInput;
const parsed = item.output && typeof item.output === 'object' ? item.output : item;
const story = analysisInput.story_text_structured ?? {};
const segments = Array.isArray(story.segments) ? story.segments : [];
const relationships = Array.isArray(normalizedInput.entity_candidates?.relationships)
  ? normalizedInput.entity_candidates.relationships
  : [];
const llmWatchouts = Array.isArray(parsed.continuity_watchouts) ? parsed.continuity_watchouts : [];

const uniqueStrings = (values) => [...new Set(
  values
    .filter((value) => typeof value === 'string')
    .map((value) => value.trim())
    .filter(Boolean),
)];

const countRecurringEntities = (selector) => {
  const counts = new Map();

  segments.forEach((segment) => {
    const values = uniqueStrings(selector(segment));
    values.forEach((value) => {
      counts.set(value, (counts.get(value) ?? 0) + 1);
    });
  });

  return [...counts.values()].filter((count) => count > 1).length;
};

const totalContinuityRisks = segments.reduce(
  (sum, segment) => sum + (Array.isArray(segment.continuity_risks) ? segment.continuity_risks.length : 0),
  0,
);

const relationshipSignalCount = segments.reduce(
  (sum, segment) => sum + (Array.isArray(segment.relationship_signals) ? segment.relationship_signals.length : 0),
  0,
);

const recurringCharacterCount = countRecurringEntities(
  (segment) => Array.isArray(segment.entities?.characters) ? segment.entities.characters : [],
);

const recurringLocationCount = countRecurringEntities(
  (segment) => Array.isArray(segment.entities?.locations) ? segment.entities.locations : [],
);

const recurringPropCount = countRecurringEntities(
  (segment) => Array.isArray(segment.entities?.props) ? segment.entities.props : [],
);

const sourceSceneIds = segments.map((segment) => segment.scene_id).filter((value) => typeof value === 'string' && value);

const relationshipPenalty = relationships.length > 0 && relationshipSignalCount === 0 ? 8 : 0;
const riskPenalty = Math.min(totalContinuityRisks * 6, 30);
const structureBonus = Math.min(Math.max(segments.length - 1, 0) * 2, 10);
const recurrenceBonus = Math.min(
  recurringCharacterCount + Math.min(recurringLocationCount, 2) + Math.min(recurringPropCount, 2),
  12,
);

const rawScore = 70 + structureBonus + recurrenceBonus - riskPenalty - relationshipPenalty;
const continuityScore = Math.max(0, Math.min(100, rawScore));

let continuityConfidence = 'medium';
if (segments.length >= 4 && totalContinuityRisks <= 2) {
  continuityConfidence = 'high';
} else if (segments.length <= 2 || totalContinuityRisks >= 4) {
  continuityConfidence = 'low';
}

const heuristicWatchouts = [];

if (totalContinuityRisks > 0) {
  heuristicWatchouts.push(`장면별 continuity_risks가 총 ${totalContinuityRisks}건 감지되어 후속 검토가 필요합니다.`);
}

if (relationships.length > 0 && relationshipSignalCount === 0) {
  heuristicWatchouts.push('관계 후보는 존재하지만 scene 단위 relationship_signals 근거가 약합니다.');
}

if (segments.length <= 1) {
  heuristicWatchouts.push('장면 수가 적어 episode-level continuity 판단 근거가 제한적입니다.');
}

if ((normalizedInput.input_metadata?.attachment_count ?? 0) > 0) {
  heuristicWatchouts.push('첨부 분석이 포함되어 있으면 continuity score 해석 범위를 별도 검토해야 합니다.');
}

const continuityWatchouts = uniqueStrings([
  ...llmWatchouts,
  ...heuristicWatchouts,
]);

const normalizedSceneFunctions = Array.isArray(parsed.scene_functions)
  ? parsed.scene_functions.map((sceneFunction, index) => {
      const requestedSceneId = typeof sceneFunction?.scene_id === 'string' ? sceneFunction.scene_id.trim() : '';
      const fallbackSceneId = sourceSceneIds[index] ?? '';
      const sceneId = sourceSceneIds.includes(requestedSceneId) ? requestedSceneId : fallbackSceneId;

      return {
        scene_id: sceneId,
        function: typeof sceneFunction?.function === 'string' ? sceneFunction.function : '',
        why_it_matters: typeof sceneFunction?.why_it_matters === 'string' ? sceneFunction.why_it_matters : '',
      };
    })
  : [];

if (Array.isArray(parsed.scene_functions) && normalizedSceneFunctions.some((sceneFunction, index) => {
  const requestedSceneId = typeof parsed.scene_functions[index]?.scene_id === 'string'
    ? parsed.scene_functions[index].scene_id.trim()
    : '';
  return requestedSceneId && requestedSceneId !== sceneFunction.scene_id;
})) {
  continuityWatchouts.push('scene_functions의 일부 scene_id가 입력 contract와 달라 입력 scene_id 기준으로 보정되었습니다.');
}

const episodeContext = {
  episode_summary: parsed.episode_summary ?? story.summary ?? '',
  central_conflict: parsed.central_conflict ?? normalizedInput.production_hints?.core_conflict ?? '',
  dramatic_question: parsed.dramatic_question ?? '',
  continuity_score: continuityScore,
  continuity_confidence: continuityConfidence,
  continuity_basis: {
    scope: 'current_episode_only',
    scoring_mode: item.scoringMode ?? 'heuristic_plus_llm',
    signals: {
      scene_count: segments.length,
      continuity_risk_count: totalContinuityRisks,
      relationship_signal_count: relationshipSignalCount,
      recurring_character_count: recurringCharacterCount,
      recurring_location_count: recurringLocationCount,
      recurring_prop_count: recurringPropCount,
    },
    limitations: [
      'prior_episode_context_unavailable',
      'series_bible_lookup_not_connected',
    ],
  },
  continuity_watchouts: continuityWatchouts,
  scene_functions: normalizedSceneFunctions,
  relationship_progressions: Array.isArray(parsed.relationship_progressions) ? parsed.relationship_progressions : [],
};

const status = segments.length > 0 ? 'ready' : 'partial';

return [{
  json: {
    ...item,
    episodeContextStatus: status,
    episodeContextInputVersion: 'v1',
    episodeContext,
  },
}];

const item = $input.first().json;
const episodeNode = item.episodeContext ? item : ($node['Assemble Episode Context']?.json ?? item);
const normalizedInput =
  episodeNode.normalizedInput
  ?? $node['Assemble Normalized Input']?.json?.normalizedInput
  ?? {};
const episodeContext = episodeNode.episodeContext ?? {};

const story = normalizedInput.story_text_structured ?? {};
const segments = Array.isArray(story.segments) ? story.segments : [];
const characterCandidates = Array.isArray(normalizedInput.entity_candidates?.characters)
  ? normalizedInput.entity_candidates.characters
  : [];
const locationCandidates = Array.isArray(normalizedInput.entity_candidates?.locations)
  ? normalizedInput.entity_candidates.locations
  : [];
const relationshipProgressions = Array.isArray(episodeContext.relationship_progressions)
  ? episodeContext.relationship_progressions
  : [];
const continuityWatchouts = Array.isArray(episodeContext.continuity_watchouts)
  ? episodeContext.continuity_watchouts
  : [];
const contextReferences = item.contextReferences ?? {
  include_recent: 0,
  specific_episodes: [],
  auto_context: false,
};

const uniqueStrings = (values) => [...new Set(
  values
    .filter((value) => typeof value === 'string')
    .map((value) => value.trim())
    .filter(Boolean),
)];

const clamp = (value, min, max) => Math.min(max, Math.max(min, value));

const buildStableId = (prefix, index) => `${prefix}_${String(index + 1).padStart(2, '0')}`;

const inferArcPhase = () => {
  if (segments.length <= 2) {
    return 'setup';
  }

  if (episodeContext.dramatic_question) {
    return 'rising_action';
  }

  return 'inciting_incident';
};

const inferCurrentEmotion = (characterName) => {
  for (let index = segments.length - 1; index >= 0; index -= 1) {
    const segment = segments[index];
    const characters = Array.isArray(segment.entities?.characters) ? segment.entities.characters : [];

    if (characters.includes(characterName)) {
      return Array.isArray(segment.emotion_tone) && segment.emotion_tone.length > 0
        ? segment.emotion_tone[0]
        : '';
    }
  }

  return '';
};

const inferRecentActions = (characterName) => uniqueStrings(
  segments.flatMap((segment) => {
    const characters = Array.isArray(segment.entities?.characters) ? segment.entities.characters : [];
    return characters.includes(characterName) && Array.isArray(segment.key_actions)
      ? segment.key_actions
      : [];
  }),
).slice(-3);

const buildCharacterContext = () => characterCandidates.map((character, index) => ({
  id: buildStableId('char', index),
  name: character.name ?? `character_${index + 1}`,
  full_profile: uniqueStrings([
    character.role ?? '',
    ...(Array.isArray(character.traits) ? character.traits : []),
  ]).join(', '),
  current_emotional_state: inferCurrentEmotion(character.name ?? ''),
  recent_actions: inferRecentActions(character.name ?? ''),
  traits: Array.isArray(character.traits) ? character.traits : [],
  reference_pack: {
    base: '',
    expressions: [],
  },
}));

const buildLocationContext = () => locationCandidates.map((location, index) => {
  const relatedSceneIds = segments
    .filter((segment) => Array.isArray(segment.entities?.locations) && segment.entities.locations.includes(location.name))
    .map((segment) => segment.scene_id)
    .filter((sceneId) => typeof sceneId === 'string' && sceneId);

  return {
    id: buildStableId('loc', index),
    name: location.name ?? `location_${index + 1}`,
    visual_spec: uniqueStrings([
      ...(Array.isArray(location.attributes) ? location.attributes : []),
      ...(Array.isArray(location.evidence) ? location.evidence : []),
    ]).join(', '),
    mood: normalizedInput.production_hints?.dominant_mood ?? '',
    reference_images: [],
    related_scene_ids: relatedSceneIds,
  };
});

const activePlotThreads = [];

if (episodeContext.dramatic_question) {
  activePlotThreads.push({
    thread_id: 'thread_main_question',
    description: episodeContext.dramatic_question,
    status: 'unresolved',
    urgency: 'high',
  });
}

relationshipProgressions.slice(0, 3).forEach((progression, index) => {
  activePlotThreads.push({
    thread_id: `thread_relationship_${index + 1}`,
    description: progression.current_implication ?? progression.change ?? '',
    status: progression.confidence === 'high' ? 'active' : 'unresolved',
    urgency: progression.confidence === 'high' ? 'medium' : 'high',
  });
});

if (continuityWatchouts.length > 0) {
  activePlotThreads.push({
    thread_id: 'thread_continuity_watchout',
    description: continuityWatchouts[0],
    status: 'warning',
    urgency: 'medium',
  });
}

const normalizedContinuityScore = clamp((episodeContext.continuity_score ?? 70) / 100, 0, 1);
const continuityPressure = Number((1 - normalizedContinuityScore).toFixed(2));
const tensionTarget = Number(clamp(
  0.45 + (activePlotThreads.length * 0.08) + (continuityWatchouts.length > 0 ? 0.05 : 0),
  0.45,
  0.95,
).toFixed(2));

const seriesContext = {
  series_id: item.seriesId ?? item.workflowName ?? 'short-drama-pipeline',
  world_setting: `${uniqueStrings(locationCandidates.map((location) => location.name)).join(', ') || '현재 에피소드 공간'} 중심의 단일 에피소드 PoC 컨텍스트`,
  themes: uniqueStrings([
    normalizedInput.production_hints?.dominant_mood ?? '',
    episodeContext.central_conflict ? '관계 붕괴' : '',
    episodeContext.dramatic_question ? '미스터리' : '',
  ]),
  tone: normalizedInput.production_hints?.dominant_mood ?? 'drama',
  total_episodes: item.totalEpisodes ?? 1,
  current_episode_number: item.currentEpisodeNumber ?? 1,
  context_mode: 'current_episode_only',
};

const planningContext = {
  series_context: seriesContext,
  character_context: buildCharacterContext(),
  location_context: buildLocationContext(),
  narrative_context: {
    arc_phase: inferArcPhase(),
    active_threads: activePlotThreads,
    tension_target: tensionTarget,
    episode_goal: episodeContext.central_conflict || episodeContext.dramatic_question || story.summary || '',
  },
  creative_constraints: {
    max_new_characters: continuityPressure >= 0.3 ? 0 : 1,
    max_new_locations: continuityPressure >= 0.5 ? 0 : 1,
    creative_freedom: Number(clamp(0.45 - continuityPressure * 0.3, 0.15, 0.45).toFixed(2)),
    continuity_priority: continuityPressure,
    context_references: contextReferences,
  },
};

return [{
  json: {
    ...episodeNode,
    planningContextStatus: 'ready',
    planningContextInputVersion: 'v1',
    planningContext,
  },
}];

const item = $input.first().json;
const planningNode = item.planningContext ? item : ($node['Context Selection Engine']?.json ?? item);

return [{
  json: {
    ...planningNode,
    storyDevelopmentInput: {
      normalized_input: planningNode.normalizedInput ?? {},
      episode_context: planningNode.episodeContext ?? {},
      planning_context: planningNode.planningContext ?? {},
    },
  },
}];

const item = $input.first().json;
const payloadNode = $node['Build Story Development Payload']?.json ?? {};
const planningNode = $node['Context Selection Engine']?.json ?? {};
const parsed = item.output && typeof item.output === 'object' ? item.output : item;
const normalizedInput =
  item.normalizedInput
  ?? payloadNode.normalizedInput
  ?? planningNode.normalizedInput
  ?? {};
const episodeContext =
  item.episodeContext
  ?? payloadNode.episodeContext
  ?? planningNode.episodeContext
  ?? {};
const planningContext =
  item.planningContext
  ?? payloadNode.planningContext
  ?? planningNode.planningContext
  ?? {};

const segments = Array.isArray(normalizedInput.story_text_structured?.segments)
  ? normalizedInput.story_text_structured.segments
  : [];
const sceneFunctions = Array.isArray(episodeContext.scene_functions)
  ? episodeContext.scene_functions
  : [];

const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const uniqueStrings = (values) => [...new Set(
  values
    .filter((value) => typeof value === 'string')
    .map((value) => value.trim())
    .filter(Boolean),
)];

const STRATEGY_ALIASES = {
  emotional_drama: 'emotional_drama',
  emotional_collapse_to_mystery: 'emotional_drama',
  relationship_drama: 'relationship_drama',
  romance_drama: 'relationship_drama',
  suspense: 'suspense_mystery',
  suspense_mystery: 'suspense_mystery',
  mystery_hook: 'suspense_mystery',
  romantic_mystery: 'romantic_mystery',
  betrayal_reveal: 'betrayal_reveal',
  betrayal_reveal_with_mystery_hook: 'betrayal_reveal',
};

const BEAT_TYPE_ALIASES = {
  setup: 'setup',
  approach: 'approach',
  catalyst: 'catalyst',
  inciting_incident: 'catalyst',
  confrontation: 'confrontation',
  confrontation_observation: 'confrontation',
  midpoint: 'midpoint',
  emotional_fallout: 'fallout',
  fallout: 'fallout',
  mystery_setup: 'mystery_setup',
  climax: 'climax',
  cliffhanger_reveal: 'climax',
  resolution: 'resolution',
};

const normalizeStrategy = (value, fallback) => {
  if (typeof value !== 'string') {
    return fallback;
  }

  return STRATEGY_ALIASES[value.trim()] ?? fallback;
};

const normalizeBeatType = (value, fallback) => {
  if (typeof value !== 'string') {
    return fallback;
  }

  return BEAT_TYPE_ALIASES[value.trim()] ?? fallback;
};

const fallbackDensityLevel = (() => {
  const sceneCount = normalizedInput.input_metadata?.scene_count ?? segments.length;
  if (sceneCount >= 8) {
    return 'high';
  }
  if (sceneCount >= 5) {
    return 'medium';
  }
  return 'low';
})();

const densityAnalysis = {
  level: parsed.density_analysis?.level ?? fallbackDensityLevel,
  rationale: parsed.density_analysis?.rationale
    ?? `${segments.length}개 안팎의 장면과 ${episodeContext.central_conflict ? '명확한 중심 갈등' : '단일 에피소드 중심 사건'}을 바탕으로 한 ${fallbackDensityLevel} 밀도 에피소드`,
};

const creativeStrategy = {
  primary: normalizeStrategy(parsed.creative_strategy?.primary, 'emotional_drama'),
  secondary: normalizeStrategy(parsed.creative_strategy?.secondary, 'suspense_mystery'),
  style_notes: parsed.creative_strategy?.style_notes
    ?? `${episodeContext.central_conflict || episodeContext.dramatic_question || '관계 변화'}를 중심으로 감정선과 긴장을 병행`,
};

const fallbackBeatSheet = sceneFunctions.map((sceneFunction, index) => {
  const segment = segments[index] ?? {};
  const beatTypes = ['setup', 'catalyst', 'confrontation', 'midpoint', 'climax', 'resolution'];
  const beatType = beatTypes[Math.min(index, beatTypes.length - 1)];
  const durationRatio = Number((1 / Math.max(sceneFunctions.length || 1, 1)).toFixed(2));
  const tension = Number(clamp(0.3 + index * 0.12, 0.2, 0.95).toFixed(2));

  return {
    beat_id: index + 1,
    type: beatType,
    description: sceneFunction.why_it_matters || segment.summary || '',
    source_scene_ids: uniqueStrings([segment.scene_id ?? sceneFunction.scene_id ?? '']),
    emotion: Array.isArray(segment.emotion_tone) && segment.emotion_tone.length > 0
      ? segment.emotion_tone[0]
      : 'neutral',
    tension,
    duration_ratio: durationRatio,
  };
});

const normalizedBeatSheet = Array.isArray(parsed.beat_sheet) && parsed.beat_sheet.length > 0
  ? parsed.beat_sheet.map((beat, index, array) => ({
      beat_id: index + 1,
      type: normalizeBeatType(
        beat?.type,
        fallbackBeatSheet[index]?.type ?? 'confrontation',
      ),
      description: typeof beat?.description === 'string' ? beat.description : '',
      source_scene_ids: uniqueStrings(
        Array.isArray(beat?.source_scene_ids) && beat.source_scene_ids.length > 0
          ? beat.source_scene_ids
          : (fallbackBeatSheet[index]?.source_scene_ids ?? []),
      ),
      emotion: typeof beat?.emotion === 'string' ? beat.emotion : 'neutral',
      tension: Number(clamp(Number(beat?.tension ?? 0.5), 0, 1).toFixed(2)),
      duration_ratio: Number(clamp(Number(beat?.duration_ratio ?? (1 / Math.max(array.length, 1))), 0.05, 0.5).toFixed(2)),
    }))
  : fallbackBeatSheet;

const emotionalArc = {
  opening_emotion: parsed.emotional_arc?.opening_emotion
    ?? normalizedBeatSheet[0]?.emotion
    ?? 'neutral',
  peak_emotion: parsed.emotional_arc?.peak_emotion
    ?? normalizedBeatSheet.reduce((best, beat) => (beat.tension > best.tension ? beat : best), normalizedBeatSheet[0] ?? { emotion: 'neutral', tension: 0 }).emotion,
  closing_emotion: parsed.emotional_arc?.closing_emotion
    ?? normalizedBeatSheet[normalizedBeatSheet.length - 1]?.emotion
    ?? 'neutral',
  arc_shape: parsed.emotional_arc?.arc_shape ?? 'rising_with_twist',
  intensity_curve: Array.isArray(parsed.emotional_arc?.intensity_curve) && parsed.emotional_arc.intensity_curve.length > 0
    ? parsed.emotional_arc.intensity_curve.map((value) => Number(clamp(Number(value), 0, 1).toFixed(2)))
    : normalizedBeatSheet.map((beat) => beat.tension),
};

return [{
  json: {
    ...item,
    storyDevelopmentStatus: normalizedBeatSheet.length > 0 ? 'ready' : 'partial',
    storyDevelopmentInputVersion: 'v1',
    storyDevelopment: {
      density_analysis: densityAnalysis,
      creative_strategy: creativeStrategy,
      beat_sheet: normalizedBeatSheet,
      emotional_arc: emotionalArc,
    },
  },
}];

const item = $input.first().json;
const storyNode = item.storyDevelopment ? item : ($node['Assemble Story Development']?.json ?? item);

return [{
  json: {
    ...storyNode,
    screenplayInput: {
      normalized_input: storyNode.normalizedInput ?? {},
      episode_context: storyNode.episodeContext ?? {},
      planning_context: storyNode.planningContext ?? {},
      story_development: storyNode.storyDevelopment ?? {},
    },
  },
}];

const item = $input.first().json;
const payloadNode = $node['Build Screenplay Payload']?.json ?? {};
const storyNode = $node['Assemble Story Development']?.json ?? {};
const parsed = item.output && typeof item.output === 'object' ? item.output : item;
const normalizedInput =
  item.normalizedInput
  ?? payloadNode.normalized_input
  ?? payloadNode.screenplayInput?.normalized_input
  ?? storyNode.normalizedInput
  ?? {};
const episodeContext =
  item.episodeContext
  ?? payloadNode.episode_context
  ?? payloadNode.screenplayInput?.episode_context
  ?? storyNode.episodeContext
  ?? {};
const planningContext =
  item.planningContext
  ?? payloadNode.planning_context
  ?? payloadNode.screenplayInput?.planning_context
  ?? storyNode.planningContext
  ?? {};
const storyDevelopment =
  item.storyDevelopment
  ?? payloadNode.story_development
  ?? payloadNode.screenplayInput?.story_development
  ?? storyNode.storyDevelopment
  ?? {};

const segments = Array.isArray(normalizedInput.story_text_structured?.segments)
  ? normalizedInput.story_text_structured.segments
  : [];
const beatSheet = Array.isArray(storyDevelopment.beat_sheet)
  ? storyDevelopment.beat_sheet
  : [];
const characters = Array.isArray(planningContext.character_context)
  ? planningContext.character_context
  : [];
const locations = Array.isArray(planningContext.location_context)
  ? planningContext.location_context
  : [];

const clamp = (value, min, max) => Math.min(max, Math.max(min, value));
const uniqueStrings = (values) => [...new Set(
  values
    .filter((value) => typeof value === 'string')
    .map((value) => value.trim())
    .filter(Boolean),
)];
const slugify = (value) => String(value ?? '')
  .trim()
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '_')
  .replace(/^_+|_+$/g, '');
const toSceneId = (index) => `sc_${String(index + 1).padStart(3, '0')}`;

const segmentById = new Map(
  segments
    .filter((segment) => typeof segment?.scene_id === 'string' && segment.scene_id)
    .map((segment) => [segment.scene_id, segment]),
);
const characterIdByName = new Map(
  characters
    .filter((character) => typeof character?.name === 'string' && typeof character?.id === 'string')
    .map((character) => [character.name, character.id]),
);

const relatedSceneIdsByLocationId = new Map(
  locations.map((location) => [
    location.id,
    Array.isArray(location.related_scene_ids) ? location.related_scene_ids : [],
  ]),
);

const inferTimeOfDay = (value) => {
  const text = String(value ?? '');

  if (text.includes('아침')) {
    return 'morning';
  }
  if (text.includes('밤')) {
    return 'night';
  }
  if (text.includes('저녁')) {
    return 'evening';
  }
  if (text.includes('낮')) {
    return 'day';
  }

  return 'unspecified';
};

const buildHeading = (segment, location) => {
  const locationName = segment?.scene_heading || location?.name || '미상 공간';
  const timeOfDay = inferTimeOfDay(segment?.scene_heading || '');
  const timeLabelMap = {
    morning: '아침',
    day: '낮',
    evening: '저녁',
    night: '밤',
    unspecified: '불명',
  };

  return `INT. ${locationName} - ${timeLabelMap[timeOfDay] ?? '불명'}`;
};

const resolveLocation = (sourceSceneIds, segment) => {
  const preferredLocationName = Array.isArray(segment?.entities?.locations) && segment.entities.locations.length > 0
    ? segment.entities.locations[0]
    : '';
  const exactByName = locations.find((location) => location.name === preferredLocationName);

  if (exactByName) {
    return exactByName;
  }

  const byScene = locations.find((location) => {
    const related = relatedSceneIdsByLocationId.get(location.id) ?? [];
    return sourceSceneIds.some((sceneId) => related.includes(sceneId));
  });

  if (byScene) {
    return byScene;
  }

  return locations[0] ?? { id: 'loc_01', name: segment?.scene_heading || '미상 공간' };
};

const resolveCharacters = (segment) => {
  const names = Array.isArray(segment?.entities?.characters) ? segment.entities.characters : [];
  const ids = uniqueStrings(names.map((name) => characterIdByName.get(name)).filter(Boolean));
  return ids.length > 0 ? ids : characters.slice(0, 1).map((character) => character.id);
};

const buildActions = (segment, characterIds, emotion) => {
  const sourceActions = Array.isArray(segment?.key_actions) ? segment.key_actions : [];
  const fallbackActions = sourceActions.length > 0 ? sourceActions : ['상황을 관찰한다'];

  return fallbackActions.slice(0, Math.max(1, Math.min(3, characterIds.length || 1))).map((detail, index) => ({
    character: characterIds[index] ?? characterIds[0] ?? (characters[0]?.id || 'char_01'),
    action: slugify(detail) || 'observe',
    emotion: emotion || 'neutral',
    detail,
  }));
};

const buildDialogue = (segment, characterIds, emotion) => {
  const summary = String(segment?.summary ?? '').trim();
  if (!summary || characterIds.length === 0) {
    return [];
  }

  return [{
    speaker: characterIds[0],
    text: `${summary.slice(0, 70)}${summary.length > 70 ? '...' : ''}`,
    tone: emotion || 'neutral',
    subtext: '현재 장면의 핵심 감정을 드러내는 요약 대사',
  }];
};

const fallbackScenes = beatSheet.map((beat, index, array) => {
  const sourceSceneIds = Array.isArray(beat.source_scene_ids) && beat.source_scene_ids.length > 0
    ? beat.source_scene_ids
    : [segments[index]?.scene_id].filter(Boolean);
  const segment = segmentById.get(sourceSceneIds[0]) ?? segments[index] ?? {};
  const location = resolveLocation(sourceSceneIds, segment);
  const charactersPresent = resolveCharacters(segment);
  const emotion = beat.emotion || (Array.isArray(segment.emotion_tone) ? segment.emotion_tone[0] : '') || 'neutral';
  const durationTargetSec = Math.round(clamp(Number(beat.duration_ratio ?? (1 / Math.max(array.length, 1))) * 90, 6, 30));

  return {
    scene_id: toSceneId(index),
    source_beats: [beat.beat_id ?? (index + 1)],
    heading: buildHeading(segment, location),
    location_id: location.id,
    time_of_day: inferTimeOfDay(segment.scene_heading || ''),
    characters_present: charactersPresent,
    description: beat.description || segment.summary || episodeContext.episode_summary || '',
    actions: buildActions(segment, charactersPresent, emotion),
    dialogue: buildDialogue(segment, charactersPresent, emotion),
    mood: {
      visual: slugify(normalizedInput.production_hints?.dominant_mood || emotion) || 'dramatic',
      audio: beat.tension >= 0.7 ? 'tense_silence' : 'ambient_room_tone',
    },
    duration_target_sec: durationTargetSec,
  };
});

const normalizedScenes = Array.isArray(parsed.scenes) && parsed.scenes.length > 0
  ? parsed.scenes.map((scene, index) => {
      const fallbackScene = fallbackScenes[index] ?? fallbackScenes[0] ?? {
        scene_id: toSceneId(index),
        source_beats: [index + 1],
        heading: 'INT. 미상 공간 - 불명',
        location_id: locations[0]?.id || 'loc_01',
        time_of_day: 'unspecified',
        characters_present: characters.slice(0, 1).map((character) => character.id),
        description: '',
        actions: [],
        dialogue: [],
        mood: { visual: 'dramatic', audio: 'ambient_room_tone' },
        duration_target_sec: 12,
      };

      const normalizedCharacters = uniqueStrings(
        Array.isArray(scene?.characters_present) ? scene.characters_present : fallbackScene.characters_present,
      );

      return {
        scene_id: toSceneId(index),
        source_beats: Array.isArray(scene?.source_beats) && scene.source_beats.length > 0
          ? scene.source_beats.map((value) => Number(value)).filter((value) => Number.isFinite(value))
          : fallbackScene.source_beats,
        heading: typeof scene?.heading === 'string' && scene.heading.trim() ? scene.heading : fallbackScene.heading,
        location_id: typeof scene?.location_id === 'string' && scene.location_id.trim()
          ? scene.location_id
          : fallbackScene.location_id,
        time_of_day: typeof scene?.time_of_day === 'string' && scene.time_of_day.trim()
          ? scene.time_of_day
          : fallbackScene.time_of_day,
        characters_present: normalizedCharacters.length > 0 ? normalizedCharacters : fallbackScene.characters_present,
        description: typeof scene?.description === 'string' ? scene.description : fallbackScene.description,
        actions: Array.isArray(scene?.actions) && scene.actions.length > 0
          ? scene.actions.map((action, actionIndex) => ({
              character: typeof action?.character === 'string' && action.character.trim()
                ? action.character
                : (normalizedCharacters[actionIndex] ?? normalizedCharacters[0] ?? fallbackScene.characters_present[0] ?? 'char_01'),
              action: slugify(action?.action) || 'observe',
              emotion: typeof action?.emotion === 'string' && action.emotion.trim()
                ? action.emotion
                : 'neutral',
              detail: typeof action?.detail === 'string' ? action.detail : '',
            }))
          : fallbackScene.actions,
        dialogue: Array.isArray(scene?.dialogue)
          ? scene.dialogue.map((line) => ({
              speaker: typeof line?.speaker === 'string' && line.speaker.trim()
                ? line.speaker
                : (normalizedCharacters[0] ?? fallbackScene.characters_present[0] ?? 'char_01'),
              text: typeof line?.text === 'string' ? line.text : '',
              tone: typeof line?.tone === 'string' && line.tone.trim() ? line.tone : 'neutral',
              subtext: typeof line?.subtext === 'string' ? line.subtext : '',
            }))
          : fallbackScene.dialogue,
        mood: {
          visual: typeof scene?.mood?.visual === 'string' && scene.mood.visual.trim()
            ? scene.mood.visual
            : fallbackScene.mood.visual,
          audio: typeof scene?.mood?.audio === 'string' && scene.mood.audio.trim()
            ? scene.mood.audio
            : fallbackScene.mood.audio,
        },
        duration_target_sec: Math.round(clamp(Number(scene?.duration_target_sec ?? fallbackScene.duration_target_sec), 5, 40)),
      };
    })
  : fallbackScenes;

const totalDurationTargetSec = normalizedScenes.reduce(
  (sum, scene) => sum + (Number(scene.duration_target_sec) || 0),
  0,
);

return [{
  json: {
    ...item,
    screenplayStatus: normalizedScenes.length > 0 ? 'ready' : 'partial',
    screenplayInputVersion: 'v1',
    screenplay: {
      scenes: normalizedScenes,
      total_scenes: normalizedScenes.length,
      total_duration_target_sec: totalDurationTargetSec,
    },
  },
}];

